class Solution:
    def findBestValue(self, arr: List[int], target: int) -> int:
        def check(val):
            return sum(min(x, val) for x in arr)

        left, right = 0, max(arr)
        res = -1
        diff = float('inf')

        while left <= right:
            mid = (left + right) // 2
            cur = abs(target - check(mid))
            if cur < diff:
                diff = cur
                res = mid
            if check(mid) < target:
                left = mid + 1
            else:
                right = mid - 1
        return res
```
